  ('social-worker-moex-01918', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '不管研究者如何小心設計問卷，仍可能會犯錯。為避免犯錯，預試（pretest）問卷很重要，下列關於預試 問卷敘述何者正確？', '["人數可以10個左右或更少，對象的背景需相似於正式問卷要調查的對象", "要用隨機抽樣的方式選取預試對象", "參加過預試問卷的對象須再受測正式問卷", "進行預試問卷時只要單純挑出錯誤就好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
